refentry.refsect1:
  &reftitle.examples;



    Пример установки силы сопоставления функцией collator_set_strength


<?php

$arr  = array('aò', 'Ao', 'ao');
$coll = collator_create('en_US');

// Сортировка массива с силой по умолчанию
collator_sort($coll, $arr);
var_export($arr);

// Сортировка массива с первичной силой
collator_set_strength($coll, Collator::PRIMARY);
collator_sort($coll, $arr);
var_export($arr);

?>


    &example.outputs;


array (
  0 => 'ao',
  1 => 'Ao',
  2 => 'aò',
)
array (
  0 => 'aò',
  1 => 'Ao',
  2 => 'ao',
)
